from sentence_transformers import SentenceTransformer, util

model = SentenceTransformer("paraphrase-multilingual-MiniLM-L12-v2")

def cross_lingual_similarity(sentences_by_lang: dict) -> list:
    all_sents, labels = [], []
    for lang, sents in sentences_by_lang.items():
        for s in sents:
            all_sents.append(s)
            labels.append(lang)

    embs = model.encode(all_sents, normalize_embeddings=True)
    sim = util.cos_sim(embs, embs)

    pairs = []
    for i in range(len(all_sents)):
        for j in range(i + 1, len(all_sents)):
            if labels[i] != labels[j]:
                pairs.append({
                    "lang_pair": f"{labels[i]}-{labels[j]}",
                    "a": all_sents[i],
                    "b": all_sents[j],
                    "score": float(sim[i][j]),
                })
    return sorted(pairs, key=lambda x: x["score"], reverse=True)

results = cross_lingual_similarity({
    "en": ["How do I reset my password?"],
    "ta": ["எனது பாஸ்வேர்டை எப்படி மீட்டமைப்பது?"],
    "fr": ["Comment réinitialiser mon mot de passe ?"],
    "ja": ["パスワードをリセットするにはどうすればいいですか？"],
})
for r in results:
    print(f"{r['lang_pair']}: {r['score']:.3f}")
